 {"id":"bd-yx9r.16.3","title":"Implement gRPC codec, service, client/server, reflection, health, and web parity","description":"Upstream gRPC spans codecs, protobuf glue, client/server/service surfaces, interceptors, reflection, health, streaming, and gRPC-web. ANSI C currently has no comparable module family.","design":"Port gRPC as a real protocol stack over the service/transport/HTTP foundations, with protobuf/reflection/health behavior and explicit integration tests.","acceptance_criteria":"A. Public gRPC modules exist across core client/server/codec/interceptor/health/reflection/web families.\\nB. Tests cover unary/streaming flows, health/reflection, interceptors, and failure handling.\\nC. Logged e2e packs show gRPC server/client success and failure cases with retained artifacts.","notes":"Depends on H1, E2, and G1.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-03-13T20:41:54.521062722Z","created_by":"ubuntu","updated_at":"2026-03-13T20:42:30.925103245Z","closed_at":"2026-03-13T20:42:30.922413150Z","close_reason":"Superseded by earlier canonical reopened parity backlog issues under bd-yx9r.7 through bd-yx9r.12","source_repo":".","compaction_level":0,"original_size":0,"labels":["crate-parity","grpc"],"dependencies":[{"issue_id":"bd-yx9r.16.3","depends_on_id":"bd-yx9r.16","type":"parent-child","created_at":"2026-03-13T20:41:54.521062722Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-yx9r.17","title":"Data, messaging, and distributed-systems parity","description":"The upstream crate also exposes database, messaging, and distributed runtime families that remain absent in ANSI C. These are not kernel details; they are concrete functional gaps visible in the exported module tree.","design":"This epic should explicitly track those gaps rather than leaving them hidden behind generic deferred-surface language.","acceptance_criteria":"A. Database, messaging, and distributed module families have explicit implementation beads with verification requirements.\\nB. Dependencies on network/service/trace/runtime layers are encoded in the graph.\\nC. Final crate-level parity cannot be declared without either implementing these or explicitly re-scoping the project.","notes":"Primary upstream references: src/database/*, src/messaging/*, src/distributed/*.","status":"closed","priority":2,"issue_type":"epic","created_at":"2026-03-13T20:41:55.235227053Z","created_by":"ubuntu","updated_at":"2026-03-13T20:42:40.462438690Z","closed_at":"2026-03-13T20:42:40.458186480Z","close_reason":"Superseded by earlier canonical reopened parity backlog issues under bd-yx9r.7 through bd-yx9r.12","source_repo":".","compaction_level":0,"original_size":0,"labels":["crate-parity","database","distributed","messaging"],"dependencies":[{"issue_id":"bd-yx9r.17","depends_on_id":"bd-yx9r","type":"parent-child","created_at":"2026-03-13T20:41:55.235227053Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
