+}
+
+TEST(encoding_config_null_safe) {
+    asx_encoding_config_init(NULL); /* should not crash */
+}
+
+/* ------------------------------------------------------------------ */
+/* Pipeline init tests                                                 */
+/* ------------------------------------------------------------------ */
